import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { usePermissions } from '../../hooks/usePermissions';
import { notifApi } from '../../services/api';
import Footer from './Footer';
import {
  Menu,
  X,
  Search,
  Bell,
  ChevronDown,
  ChevronRight,
  LogOut,
  LayoutDashboard,
  FolderOpen,
  PlusCircle,
  ClipboardCheck,
  BarChart3,
  Users,
  Settings,
  Calculator,
  User,
  Shield,
  FileText
} from 'lucide-react';
import './Layout.css';

export default function Layout({ children }) {
  const { user, logout } = useAuth();
  const perms = usePermissions();
  const location = useLocation();
  const navigate = useNavigate();

  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [activeMenu, setActiveMenu] = useState('');
  const [activeDesktopMenu, setActiveDesktopMenu] = useState(null);
  const [userDropdownOpen, setUserDropdownOpen] = useState(false);
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 1024);
  const [searchOpen, setSearchOpen] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);
  const [searchQuery, setSearchQuery] = useState('');
  const [notifDropdownOpen, setNotifDropdownOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [loadingNotifs, setLoadingNotifs] = useState(false);

  const searchInputRef = useRef(null);
  const userMenuRef = useRef(null);
  const desktopSubmenuRef = useRef(null);
  const sidebarRef = useRef(null);
  const submenuTimerRef = useRef(null);

  useEffect(() => {
    notifApi.list().then(data => setUnreadCount(data.filter(n => !n.is_read).length)).catch(() => { });
    const interval = setInterval(() => {
      notifApi.list().then(data => setUnreadCount(data.filter(n => !n.is_read).length)).catch(() => { });
    }, 60000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth <= 1024;
      setIsMobile(mobile);
      if (!mobile) setSidebarOpen(false);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (userDropdownOpen && userMenuRef.current && !userMenuRef.current.contains(event.target)) {
        setUserDropdownOpen(false);
      }

      if (notifDropdownOpen && !event.target.closest('.notifications-header-container')) {
        setNotifDropdownOpen(false);
      }

      // Fix: Close active desktop menu when clicking outside, but ignore clicks on the sidebar buttons themselves
      if (activeDesktopMenu &&
        desktopSubmenuRef.current &&
        !desktopSubmenuRef.current.contains(event.target) &&
        !event.target.closest('.desktop-nav-link')) {
        setActiveDesktopMenu(null);
      }

      if (searchOpen && !event.target.closest('.search-container')) {
        setSearchOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      if (submenuTimerRef.current) clearTimeout(submenuTimerRef.current);
    };
  }, [userDropdownOpen, activeDesktopMenu, searchOpen]);

  const allMenuSections = useMemo(() => [
    {
      title: "Navigation",
      items: [
        { id: 'dashboard', name: 'Dashboard', icon: LayoutDashboard, path: '/dashboard', single: true },
        {
          id: 'cases-menu',
          name: 'Cases Management',
          icon: FolderOpen,
          permission: 'canViewAllCases',
          subItems: [
            { name: 'All Cases', path: '/cases', icon: FileText, permission: 'canViewAllCases' },
            { name: 'New Case', path: '/cases/new', icon: PlusCircle, permission: 'canSubmitCases' },
            { name: 'My Assignments', path: '/cases/assigned', icon: ClipboardCheck, permission: 'canSubmitAssessment' }
          ]
        },
        { id: 'reports', name: 'Reports Center', icon: BarChart3, path: '/reports', single: true, permission: 'canViewReports' }
      ]
    },
    {
      title: "System Configuration",
      items: [
        {
          id: 'system-menu',
          name: 'Configuration',
          icon: Settings,
          permission: 'canManageUsers',
          subItems: [
            { name: 'User Directory', path: '/users', icon: Users, permission: 'canManageUsers' },
            { name: 'Calculation Formulas', path: '/formulas', icon: Calculator, permission: 'canManageFormulas' }
          ]
        }
      ]
    }
  ], []);

  const menuSections = useMemo(() => {
    return allMenuSections.map(section => ({
      ...section,
      items: section.items.filter(item => {
        if (item.permission && !perms[item.permission]) return false;
        if (item.subItems) {
          item.subItems = item.subItems.filter(sub => !sub.permission || perms[sub.permission]);
          return item.subItems.length > 0;
        }
        return true;
      })
    })).filter(s => s.items.length > 0);
  }, [allMenuSections, perms]);



  const activeDesktopMenuItem = useMemo(() => {
    if (!activeDesktopMenu) return null;
    for (const section of menuSections) {
      for (const item of section.items) {
        if (item.id === activeDesktopMenu) return item;
      }
    }
    return null;
  }, [activeDesktopMenu, menuSections]);

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  const getUserInitials = () => {
    if (user?.full_name) {
      const parts = user.full_name.split(' ');
      return (parts.length > 1 ? parts[0][0] + parts[1][0] : parts[0].substring(0, 2)).toUpperCase();
    }
    return 'U';
  };

  const fetchNotifications = useCallback(async () => {
    setLoadingNotifs(true);
    try {
      const data = await notifApi.list();
      setNotifications(data.slice(0, 5)); // Show only latest 5
      setUnreadCount(data.filter(n => !n.is_read).length);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingNotifs(false);
    }
  }, []);

  const handleToggleNotifs = () => {
    if (!notifDropdownOpen) {
      fetchNotifications();
    }
    setNotifDropdownOpen(!notifDropdownOpen);
  };

  const handleMarkRead = async (id) => {
    try {
      await notifApi.markRead(id);
      setNotifications(prev => prev.map(n => n.id === id ? { ...n, is_read: true } : n));
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (err) { }
  };

  const toggleSidebar = () => setSidebarOpen(!sidebarOpen);
  const closeSidebar = () => setSidebarOpen(false);

  // Close desktop submenu
  const closeDesktopMenu = () => setActiveDesktopMenu(null);

  return (
    <div className="layout">
      {/* Top Navbar */}
      <nav className="top-navbar visible">
        <div className="navbar-content">
          <div className="left-section">
            {isMobile && (
              <button className="mobile-menu-btn" onClick={toggleSidebar}>
                <Menu size={20} />
              </button>
            )}
            <div className="logo-text-container" onClick={() => navigate('/dashboard')} style={{ cursor: 'pointer' }}>
              <img src="/police_logo.png" alt="Logo" className="police-logo" />
              <div className="brand-divider">|</div>
              <span className="brand-text">Compensation Management</span>
            </div>
          </div>

          <div className="right-section">
            <div className="search-container">
              {searchOpen ? (
                <div className="search-bar">
                  <Search size={16} className="search-icon" />
                  <input
                    ref={searchInputRef}
                    className="search-input"
                    placeholder="Quick Search..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    autoFocus
                  />
                  <button className="search-close-btn" onClick={() => setSearchOpen(false)}><X size={14} /></button>
                </div>
              ) : (
                <button className="search-btn" onClick={() => { setSearchOpen(true); setTimeout(() => searchInputRef.current?.focus(), 100); }}>
                  <Search size={20} />
                </button>
              )}
            </div>

            <div className="notifications-header-container">
              <button className="notifications-header-btn" onClick={handleToggleNotifs}>
                <Bell size={20} />
                {unreadCount > 0 && <span className="notification-badge-header">{unreadCount}</span>}
              </button>

              {notifDropdownOpen && (
                <div className="notif-dropdown-popup">
                  <div className="notif-dropdown-header">
                    <span>Recent Notifications</span>
                    {unreadCount > 0 && <span className="notif-unread-tag">{unreadCount} New</span>}
                  </div>
                  <div className="notif-dropdown-list">
                    {loadingNotifs ? (
                      <div className="notif-empty-state">Loading...</div>
                    ) : notifications.length > 0 ? (
                      notifications.map(n => (
                        <div 
                          key={n.id} 
                          className={`notif-item ${!n.is_read ? 'unread' : ''}`}
                          onClick={() => {
                            if (!n.is_read) handleMarkRead(n.id);
                            
                            // Build the link from the case data if available
                            const caseId = n.corresponding_case?.case_id;
                            if (caseId) {
                              navigate(`/cases/${caseId}`);
                            } else if (n.link) {
                              navigate(n.link);
                            }
                            
                            setNotifDropdownOpen(false);
                          }}
                        >
                          <div className="notif-icon-circle">
                            <Bell size={14} />
                          </div>
                          <div className="notif-content">
                            <div className="notif-title">{n.title}</div>
                            <div className="notif-message">{n.message}</div>
                            <div className="notif-time">{new Date(n.created_at).toLocaleDateString()}</div>
                          </div>
                          {!n.is_read && <div className="unread-dot" />}
                        </div>
                      ))
                    ) : (
                      <div className="notif-empty-state">No notifications found</div>
                    )}
                  </div>
                  <div className="notif-dropdown-footer">
                    <button onClick={() => { navigate('/notifications'); setNotifDropdownOpen(false); }}>
                      View All Notifications
                    </button>
                  </div>
                </div>
              )}
            </div>

            <div className="profile-avatar-container" ref={userMenuRef}>
              <button className="profile-avatar-btn" onClick={() => setUserDropdownOpen(!userDropdownOpen)}>
                <span className="profile-initials-nav">{getUserInitials()}</span>
              </button>
              {userDropdownOpen && (
                <div className="profile-dropdown-popup">
                  <div className="profile-dropdown-header">
                    <div className="profile-dropdown-avatar">
                      <span className="profile-dropdown-initials">{getUserInitials()}</span>
                    </div>
                    <div className="profile-dropdown-info">
                      <div className="profile-dropdown-name">{user?.full_name}</div>
                      <div className="profile-dropdown-role">{user?.rank || 'System User'}</div>
                    </div>
                  </div>
                  <div className="profile-dropdown-menu">
                    <button className="profile-dropdown-item" onClick={() => { navigate('/profile'); setUserDropdownOpen(false); }}>
                      <User size={16} /> Profile
                    </button>
                    <button className="profile-dropdown-item logout-item" onClick={handleLogout}>
                      <LogOut size={16} /> Logout
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </nav>

      {/* Mobile Sidebar Navigation */}
      {isMobile && sidebarOpen && (
        <div className="sidebar-overlay" onClick={closeSidebar}>
          <aside className="mobile-sidebar open" onClick={e => e.stopPropagation()} ref={sidebarRef}>
            <div className="sidebar-header">
              <div className="sidebar-brand">
                <img src="/police_logo.png" className="sidebar-logo" alt="Logo" />
                <h2 className="sidebar-title">Compensation Management</h2>
              </div>
              <button className="sidebar-close-btn" onClick={closeSidebar}><X size={18} /></button>
            </div>
            <nav className="sidebar-nav">
              {menuSections.map((section, idx) => (
                <div key={idx} className="nav-section">
                  <div className="section-title">{section.title}</div>
                  <div className="nav-items">
                    {section.items.map((item, i) => (
                      <div key={i} className="nav-item-wrapper">
                        {item.single ? (
                          <Link to={item.path} className={`sidebar-nav-item ${location.pathname === item.path ? 'active' : ''}`} onClick={closeSidebar}>
                            <div className="nav-item-icon"><item.icon size={16} /></div>
                            <span className="nav-item-text">{item.name}</span>
                          </Link>
                        ) : (
                          <>
                            <button className={`sidebar-nav-item nav-toggle ${activeMenu === item.name ? 'active' : ''}`} onClick={() => setActiveMenu(activeMenu === item.name ? '' : item.name)}>
                              <div className="nav-item-icon"><item.icon size={16} /></div>
                              <span className="nav-item-text">{item.name}</span>
                              <ChevronDown size={12} className={`nav-arrow ${activeMenu === item.name ? 'rotate' : ''}`} />
                            </button>
                            <div className={`nav-submenu ${activeMenu === item.name ? 'show' : ''}`}>
                              {item.subItems.map((sub, j) => (
                                <Link key={j} to={sub.path} className={`nav-sublink ${location.pathname === sub.path ? 'active' : ''}`} onClick={closeSidebar}>
                                  <div className="nav-item-icon"><sub.icon size={14} /></div>
                                  <span className="nav-item-text">{sub.name}</span>
                                </Link>
                              ))}
                            </div>
                          </>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </nav>
            <div className="sidebar-footer">
              <button className="logout-btn-sidebar" onClick={handleLogout}>
                <LogOut size={14} /> <span>Logout</span>
              </button>
            </div>
          </aside>
        </div>
      )}

      {/* Desktop Sidebar & Submenu Navigation */}
      {!isMobile && (
        <>
          <aside className="desktop-sidebar">
            <nav className="desktop-sidebar-nav">
              <div className="desktop-nav-item">
                <button
                  className={`desktop-nav-link ${location.pathname === '/dashboard' ? 'active' : ''}`}
                  onClick={() => { navigate('/dashboard'); setActiveDesktopMenu(null); }}
                  aria-label="Dashboard"
                >
                  <LayoutDashboard size={18} />
                </button>
              </div>

              {menuSections.map(section => (
                section.items.map(item => (
                  !item.single && (
                    <div key={item.id} className="desktop-nav-item">
                      <button
                        className={`desktop-nav-link ${activeDesktopMenu === item.id ? 'active' : ''}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          setActiveDesktopMenu(activeDesktopMenu === item.id ? null : item.id);
                        }}
                      >
                        <item.icon size={18} />
                      </button>
                    </div>
                  )
                ))
              ))}

              {menuSections.some(s => s.items.some(i => i.id === 'reports')) && (
                <div className="desktop-nav-item">
                  <button
                    className={`desktop-nav-link ${location.pathname === '/reports' ? 'active' : ''}`}
                    onClick={() => { navigate('/reports'); closeDesktopMenu(); }}
                  >
                    <BarChart3 size={18} />
                  </button>
                </div>
              )}

              <div className="sidebar-divider"></div>

              <div className="desktop-nav-item">
                <button className="desktop-nav-link" onClick={() => { navigate('/profile'); closeDesktopMenu(); }}><User size={18} /></button>
              </div>
              <div className="desktop-nav-item">
                <button className="desktop-nav-link logout-desktop" onClick={() => { handleLogout(); closeDesktopMenu(); }}><LogOut size={18} /></button>
              </div>
            </nav>
          </aside>

          {activeDesktopMenu && activeDesktopMenuItem && (
            <div
              ref={desktopSubmenuRef}
              className="desktop-submenu show"
              style={{ left: '80px' }}
            >
              <div className="submenu-header">
                <div className="submenu-title">
                  <activeDesktopMenuItem.icon size={16} className="submenu-title-icon" />
                  <h3>{activeDesktopMenuItem.name}</h3>
                </div>
              </div>
              <div className="submenu-content">
                <div className="submenu-items">
                  {activeDesktopMenuItem.subItems.map((sub, idx) => (
                    <button key={idx} className={`submenu-item ${location.pathname === sub.path ? 'active' : ''}`} onClick={() => { navigate(sub.path); closeDesktopMenu(); }}>
                      <div className="submenu-item-icon"><sub.icon size={14} /></div>
                      <span className="submenu-item-text">{sub.name}</span>
                      {location.pathname === sub.path && <ChevronRight size={12} className="active-indicator" />}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}
        </>
      )}

      {/* Main Content Render */}
      <main className={`main-content ${isMobile ? 'mobile-view' : ''}`}>
        <div className="content-wrapper">
          {children}
        </div>
        <Footer />
      </main>
    </div>
  );
}
